export interface FileAnnotation {
  type: 'file'
  source: FileAnnotationSource
}

export interface UrlAnnotationSource {
  type: 'url'
  url: string
}

export interface UrlAnnotation {
  type: 'url'
  source: UrlAnnotationSource
}

export interface ResponseOutputText {
  type: 'output_text'
  text: string
  annotations: FileAnnotation | UrlAnnotation[]
}

export interface AssistantMessageItem {
  id: string
  object: 'chatkit.thread_item'
  created_at: number
  thread_id: string
  type: 'chatkit.assistant_message'
  content: ResponseOutputText[]
}

export interface WidgetMessageItem {
  id: string
  object: 'chatkit.thread_item'
  created_at: number
  thread_id: string
  type: 'chatkit.widget'
  widget: string
}

export type ClientToolCallStatus = 'in_progress' | 'completed'
export const ClientToolCallStatusValues = ['in_progress', 'completed'] as const

export interface ClientToolCallItem {
  id: string
  object: 'chatkit.thread_item'
  created_at: number
  thread_id: string
  type: 'chatkit.client_tool_call'
  status: ClientToolCallStatus
  call_id: string
  name: string
  arguments: string
  output: string | null
}

export type TaskType = 'custom' | 'thought'
export const TaskTypeValues = ['custom', 'thought'] as const

export interface TaskItem {
  id: string
  object: 'chatkit.thread_item'
  created_at: number
  thread_id: string
  type: 'chatkit.task'
  task_type: TaskType
  heading: string | null
  summary: string | null
}

export interface TaskGroupTask {
  type: TaskType
  heading: string | null
  summary: string | null
}

export interface TaskGroupItem {
  id: string
  object: 'chatkit.thread_item'
  created_at: number
  thread_id: string
  type: 'chatkit.task_group'
  tasks: TaskGroupTask[]
}

export type ThreadItem =
  | (UserMessageItem & { type: 'userMessageItem' })
  | (AssistantMessageItem & { type: 'assistantMessageItem' })
  | (WidgetMessageItem & { type: 'widgetMessageItem' })
  | (ClientToolCallItem & { type: 'clientToolCallItem' })
  | (TaskItem & { type: 'taskItem' })
  | (TaskGroupItem & { type: 'taskGroupItem' })

export interface ThreadItemListResource {
  object: 'list'
  data: ThreadItem[]
  first_id: string | null
  last_id: string | null
  has_more: boolean
}

export interface ActiveStatus {
  type: 'active'
}

export interface LockedStatus {
  type: 'locked'
  reason: string | null
}

export interface ClosedStatus {
  type: 'closed'
  reason: string | null
}

export interface ThreadResource {
  id: string
  object: 'chatkit.thread'
  created_at: number
  title: string | null
  status: ActiveStatus | LockedStatus | ClosedStatus
  user: string
}

export interface DeletedThreadResource {
  id: string
  object: 'chatkit.thread.deleted'
  deleted: boolean
}

export interface ThreadListResource {
  object: 'list'
  data: ThreadResource[]
  first_id: string | null
  last_id: string | null
  has_more: boolean
}

export interface DragPoint {
  x: number
  y: number
}
